func cosineSimilarity(a: [Double], b: [Double]) -> Double {
  let numerator = zip(a, b).map(*).reduce(0, +)
  let denominator = sqrt(a.map { $0 * $0 }.reduce(0, +)) * sqrt(b.map { $0 * $0 }.reduce(0, +))
  return numerator / denominator
}
